from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about universities (or related entities) into a single,
    fluent sentence. Handles multiple triples by creating a clause for each and joining
    them with commas and a final conjunction.
    """
    if not triples:
        return ""

    clauses: list[str] = []
    for t in triples:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Simple verb mapping for common predicates
        if pred in {"city", "country", "state", "location", "capital", "largestCity",
                    "river", "hasToItsNortheast", "hasToItsWest",
                    "hasToItsNorthwest", "neighboringMunicipality", "isPartOf"}:
            clause = f"{subj} is in {obj}"
        elif pred == "established":
            clause = f"{subj} was established in {obj}"
        elif pred == "postalCode":
            clause = f"The postal code of {subj} is {obj}"
        elif pred == "elevationAboveTheSeaLevel":
            clause = f"{subj} lies at an elevation of {obj} metres above sea level"
        elif pred in {"rector", "dean", "director", "president", "leader",
                      "headquarter", "founder"}:
            clause = f"The {pred} of {subj} is {obj}"
        elif pred in {"nickname", "latinName", "motto", "anthem",
                      "patronSaint", "religion"}:
            clause = f"The {pred} of {subj} is \"{obj}\""
        elif pred in {"academicStaffSize", "numberOfStudents",
                      "numberOfPostgraduateStudents", "numberOfUndergraduateStudents",
                      "numberOfDoctoralStudents", "staff", "outlookRanking"}:
            clause = f"{subj} has {obj} {pred}"
        else:
            # Fallback generic phrasing
            clause = f"{subj} {pred} {obj}"

        clauses.append(clause)

    # Combine clauses into one sentence
    if len(clauses) == 1:
        return clauses[0] + "."
    else:
        return ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

# EVOLVE-BLOCK-END

